var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"짠! 도착!","JPN":"ジャーン！　到着！","ENG":"Ta-da! I'm here!","TWN":"鏘！到達！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"내가 좀 늦었지? 고등부는 시험기간이라고 연장수업을 시켜서 말이야.","JPN":"待たせちゃったね。高等部は\\n試験期間だから補修授業があってさ。","ENG":"Sorry I'm a bit late. They extended our classes in high school since it's exam season.","TWN":"我來晚了嗎？高中部在考試期間都會晚下課。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"얼른 부실 청소를......","JPN":"さっさとサークル室の掃除を……","ENG":"I'll start cleaning the room...","TWN":"我得快點打掃才行……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응?","JPN":"えっ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"......크르릉?!","JPN":"……グルル！？","ENG":"Grrr?!","TWN":"……嗷唔？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_01"},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으아악?!!","JPN":"うわっ！？","ENG":"Ahhh?!","TWN":"呀啊啊？！！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"고, 곰이다! 곰이 빗자루질을 하고 있어?!","JPN":"ク、クマ！　クマがホウキを持ってる！？","ENG":"A b-bear! A bear is sweeping the floor?!","TWN":"有、有熊啊！熊竟然在用掃把掃地？！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아, 호진 언니! 오셨어요?","JPN":"あ、マユミさん！　遅かったですね？","ENG":"Oh, Hojin! You're here.","TWN":"啊，鎬眞姐姐！妳來了啊？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"하림아 도망쳐! 곰이야! 곰이라고!","JPN":"ウサギちゃん、逃げて！　クマよ、クマが出た！","ENG":"Harim, run! It's a bear! A bear!","TWN":"夏琳快逃！熊！有熊啊！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아, 괜찮아요. 저건 고미가 답답하다고 해서 원래 모습으로 잠시 바꿔놓은 거 거든요.","JPN":"あ、大丈夫ですよ。クマたんが息苦しいって言うから、少しの間だけ元の姿に戻してるんです。","ENG":"Oh, it's okay. Teddy's been feeling a bit stuffy, so I just turned her back to her original form for a bit.","TWN":"啊，沒事啦。那是咕美熊熊說太無聊了，所以想暫時變回原來的樣子。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"자, 이제 휴식시간은 끝! 돌아와!","JPN":"さぁ、休憩時間は終わり！　戻ってきて！","ENG":"Alright, that's the end of your break! Come back!","TWN":"好了，休息時間結束了！回來吧！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BEAR_SUMMON_NULL_NULL","text":{"KOREA":"삑! 삐삑!","JPN":"ピッ！　ピッ！","ENG":"Beep! Be-beep!","TWN":"嗶！嗶嗶！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"이, 이게...... 그 무시무시한 곰이었다고?","JPN":"こ、これが……あの恐ろしいクマだったの？","ENG":"Th-this... was that scary looking bear?","TWN":"那、那是……剛剛那隻可怕的熊？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇다. 고미 대원은 원래 버추얼 월드에서 온 풍부한 실전 경험을 가진 물리 마법사로서 베테랑 솔저인 나도 많은 지도편달을 받고 있지.","JPN":"そうだ。クマたん隊員はバーチャルワールドから来た豊富な実戦経験を持つ\\n物理魔法使いで、ベテランソルジャーの本官も多くの指導を受けている。","ENG":"That's right. Teddy is a seasoned physical-type wizard from the virtual world. Even I have a lot to learn from Teddy despite being a veteran soldier.","TWN":"是啊。咕美熊熊隊員是來自虛擬世界，擁有豐富實戰經驗的物理法師，就是身為老兵的我也受到牠很多指導和鞭策呢。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"버추얼 월드......?! 정말로 그런 게 있어?","JPN":"バーチャルワールド……！？　本当にそんなものがあるの？","ENG":"The virtual world?! That really exists?","TWN":"虛擬世界……？！真的有這種東西嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"정확히는 <color=#ffd34c>시계 속 동물원</color>이에요. 소림이는 이 어플을 자꾸 이상한 이름으로 부른다니까.","JPN":"正確には<color=#ffd34c>時計の中の動物園</color>です。\\nミズキったら、このアプリをいつも変な名前で呼ぶんだから！","ENG":"To be exact, it's a <color=#ffd34c>zoo inside my Watch</color>. Sorim just made up a weird name for this application.","TWN":"正確來說是<color=#ffd34c>鐘錶中的動物園</color>，但蕭林總一直用奇怪的名字稱呼這個應用程式。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하, 하지만 그게 더 멋있는걸......","JPN":"し、しかしその方がもっとカッコイイ……","ENG":"B-but it sounds a lot cooler...","TWN":"但、但是那個名字更帥啊……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그럼 아까 그 커다란 곰을 이런 작은 모습으로 바꿔둔 거야?","JPN":"さっきの大きなクマが、\\nこんな小さくてカワイイ姿になっちゃった。","ENG":"Then that huge bear from before transformed into this cute form?","TWN":"所以妳把剛才的大熊變成了這麼小的樣子？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"전부터 느껴왔던 건데......","JPN":"前から感じてたけど……","ENG":"I always knew, but...","TWN":"我從之前就一直覺得……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"하림이는 정말 디자인 센스가 좋구나!","JPN":"ウサギちゃんってやっぱりデザインセンスあると思う！","ENG":"you make incredible designs, Harim!","TWN":"夏琳的設計感真的很好呢！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그쵸?","JPN":"私もそう思います！","ENG":"Right?","TWN":"對吧？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아 참. 그러고 보니 언니는 이 아이들 원래 모습도 본 적이 없겠네요?","JPN":"あっ、そういえばマユミさんは\\nこの子たちの本来の姿を見たことないですよね？","ENG":"Oh. I guess you haven't seen the original form of these guys either.","TWN":"對了，這麼說來，姐姐還沒有見過這些孩子原本的樣子吧？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그럼 말 나온 김에 모두 소개해 드릴게요!","JPN":"いい機会ですし、お見せしますね！","ENG":"Since we're on the topic, I'll introduce you to them!","TWN":"那就趁這個機會向妳介紹一下吧！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"여기 이 <color=#ffd34c>더쿠</color>랑 <color=#ffd34c>토리</color>도 평소의 모습이랑은 다르게 사실은......","JPN":"この<color=#ffd34c>ダック</color>と<color=#ffd34c>トリ</color>も、本来の姿と違って……","ENG":"Here, this is <color=#ffd34c>Ducky</color> and <color=#ffd34c>Hopper</color>. They originally look like...","TWN":"這是<color=#ffd34c>德庫</color>和<color=#ffd34c>托里</color>，跟牠們平時的樣子也不一樣，事實上……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아, 아니야 아니야! 안 보여줘도 괜찮아!","JPN":"う、ううん！　見せてくれなくてもいい！","ENG":"N-no! No! I'm good!","TWN":"啊，不用不用！不用給我看也沒關係！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"세상엔 가끔 모르는 편이 더 아름다운 것도 있는 법이거든......","JPN":"この世には知らない方が\\nもっと美しく見えることもあるからさ。","ENG":"There are things in this world that are best left unseen...","TWN":"世界上有時也有不知道會比較好的事情……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};